                              const std::string& password);
  absl::Status loadPkcs12(const std::string& data, const std::string& data_path,
                          const std::string& password);
  absl::Status checkPrivateKey(const bssl::UniquePtr<EVP_PKEY>& pkey, const std::string& key_path);
};
